            let y1 = points[i][1];
            let x2 = points[j][0];
            let y2 = points[j][1];
            let dx = x2 - x1;
            let dy = y2 - y1;

            if dx == 0 {
                // Vertical line, infinite slope
                slope_map.entry((0, 1)).or_insert(0);
            } else {
